<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  body,html{margin:0;padding:0;height:100%;overflow:hidden;background:#2e3436;color:white;font-family:sans-serif;}
  #desktop{position:absolute;top:0;left:0;width:100%;height:100%;background:url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="400"><rect width="400" height="400" fill="%232e3436"/><circle cx="200" cy="200" r="150" fill="%23383838"/></svg>') center/cover;}
  #taskbar{position:absolute;bottom:0;left:0;width:100%;height:40px;background:#3c3f41;display:flex;align-items:center;padding-left:10px;}
  .launcher{margin-right:8px;padding:4px 8px;border-radius:4px;background:#5e6266;color:white;cursor:pointer;}
  .window{position:absolute;top:50px;left:50px;width:400px;height:300px;background:#2e3436;border:1px solid #555;border-radius:4px;box-shadow:0 0 10px rgba(0,0,0,.5);display:none;}
  .win-header{background:#3c3f41;padding:4px 8px;font-weight:bold;cursor:pointer;user-select:none;display:flex;justify-content:space-between;align-items:center;}
  .win-close{color:white;background:none;border:none;cursor:pointer;font-size:16px;}
  #files-window, #notepad-window{width:500px;height:400px;}
  /* Files app */
  #files-path{padding:4px 8px;background:#3c3f41;}
  #file-list{padding:8px;overflow:auto;height:calc(100% - 80px);}
  .fs-item{cursor:pointer;padding:2px 0;}
  .fs-item:hover{background:#555;}
  /* Notepad app */
  #tabs{display:flex;background:#3c3f41;border-bottom:1px solid #555;}
  .tab{padding:4px 8px;margin-right:2px;cursor:pointer;color:white;}
  .tab.active{background:#5e6266;}
  #new-tab{margin-left:auto;padding:4px 8px;background:#5e6266;color:white;border:none;cursor:pointer;}
  #editor{width:100%;height:calc(100% - 30px);border:none;background:#2e3436;color:white;font-family:monospace;font-size:14px;}
</style>
</head>
<body>
<div id="desktop"></div>

<div id="taskbar">
  <button class="launcher" id="open-files">Files</button>
  <button class="launcher" id="open-notepad">Notepad</button>
</div>

<!-- Files Window -->
<div id="files-window" class="window">
  <div class="win-header">
    <span>Files</span>
    <button class="win-close">&times;</button>
  </div>
  <div id="files-path">/</div>
  <div id="file-list"></div>
</div>

<!-- Notepad Window -->
<div id="notepad-window" class="window">
  <div class="win-header">
    <span>Notepad</span>
    <button class="win-close">&times;</button>
  </div>
  <div id="tabs"></div>
  <textarea id="editor"></textarea>
</div>

<script>
/* ---------- Utility ---------- */
function $(id){return document.getElementById(id);}
function create(path, type){return {name:path.split('/').pop(), path,type};}

/* ---------- Files App ---------- */
const fileSystem = {
  '/': ['bin','etc','home','usr','var'],
  '/home': ['user'],
  '/home/user': ['Documents','Downloads','Pictures']
};
let currentPath = '/';

function renderFiles(){
  const list=$('file-list');
  list.innerHTML='';
  $('files-path').textContent=currentPath;
  const items=fileSystem[currentPath]||[];
  items.forEach(name=>{
    const div=document.createElement('div');
    div.className='fs-item';
    div.textContent=name;
    div.dataset.path=currentPath+'/'+name;
    if(fileSystem[div.dataset.path]){ // folder
      div.addEventListener('dblclick',()=>navigate(div.dataset.path));
    }
    list.appendChild(div);
  });
}
function navigate(path){
  currentPath=path;
  renderFiles();
}
$('files-up')?.addEventListener('click',()=>{
  if(currentPath!=='/') navigate(currentPath.split('/').slice(0,-1).join('/')||'/');
});
renderFiles();

/* ---------- Notepad App ---------- */
let tabs=[];
let activeIndex=0;

function loadTabs(){
  const data=localStorage.getItem('notepad-tabs');
  if(data){tabs=JSON.parse(data);}else{tabs=[{title:'Untitled',content:''}];}
  renderTabs();
  switchTab(0);
}
function saveTabs(){localStorage.setItem('notepad-tabs',JSON.stringify(tabs));}

function renderTabs(){
  const tabsDiv=$('tabs');
  tabsDiv.innerHTML='';
  tabs.forEach((t,i)=>{
    const tab=document.createElement('div');
    tab.className='tab'+(i===activeIndex?' active':'');
    tab.textContent=t.title;
    tab.dataset.index=i;
    tab.addEventListener('click',()=>switchTab(i));
    tabsDiv.appendChild(tab);
  });
}
function switchTab(index){
  activeIndex=index;
  $('editor').value=tabs[index].content;
  renderTabs();
}
$('new-tab').addEventListener('click',()=>{
  const title='Untitled '+(tabs.length+1);
  tabs.push({title,content:''});
  switchTab(tabs.length-1);
  saveTabs();
});
$('editor').addEventListener('input',()=>{tabs[activeIndex].content=$('editor').value;saveTabs();});

/* ---------- Window Controls ---------- */
function showWindow(id){
  $(id).style.display='block';
}
function hideWindow(id){
  $(id).style.display='none';
}
$('#open-files').addEventListener('click',()=>showWindow('files-window'));
$('#open-notepad').addEventListener('click',()=>{showWindow('notepad-window');loadTabs();});
$('.win-close').forEach(btn=>btn.addEventListener('click',function(){hideWindow(this.parentElement.parentElement.id);}));

/* ---------- Dragging (basic) ---------- */
document.querySelectorAll('.window').forEach(win=>{
  const header=win.querySelector('.win-header');
  let offsetX,offsetY;
  header.addEventListener('mousedown',e=>{
    offsetX=e.clientX-win.offsetLeft;
    offsetY=e.clientY-win.offsetTop;
    document.body.style.userSelect='none';
  });
  document.addEventListener('mousemove',e=>{
    if(e.buttons!==1)return;
    win.style.left=(e.clientX-offsetX)+'px';
    win.style.top=(e.clientY-offsetY)+'px';
  });
  document.addEventListener('mouseup',()=>{document.body.style.userSelect='auto';});
});
</script>
</body>
</html>
